SELECT
  title || ' ' || first_name || ' ' || last_name AS puno_ime
FROM professors;

SELECT *
FROM students
WHERE enrollment_year = 2022;

SELECT *
FROM subjects
WHERE ects >= 6;

SELECT *
FROM professors
WHERE last_name LIKE 'P%';

SELECT *
FROM subjects
ORDER BY ects DESC;

SELECT *
FROM subjects
LIMIT 5;

SELECT first_name, last_name, email
FROM professors
WHERE title = 'docent';

SELECT *
FROM faculties
WHERE city = 'Beograd';

SELECT first_name, last_name, email
FROM professors
WHERE email ILIKE '%etf%';

SELECT first_name, last_name, title
FROM professors
ORDER BY last_name ASC;

SELECT *
FROM exams
ORDER BY grade DESC;

SELECT name, city
FROM faculties
ORDER BY name ASC;

SELECT first_name, last_name, enrollment_year
FROM students
ORDER BY enrollment_year ASC;

SELECT name, faculty_id, semester, ects
FROM subjects
ORDER BY faculty_id ASC, ects DESC;

SELECT title, first_name, last_name
FROM professors
ORDER BY title ASC, last_name ASC;

SELECT first_name, last_name, department_id
FROM students
ORDER BY department_id ASC NULLS LAST;

SELECT COUNT(*) AS passed_exams
FROM exams
WHERE passed = true;

SELECT ROUND(AVG(grade), 2) AS avg_passing_grade
FROM exams
WHERE passed = true;

SELECT SUM(ects) AS total_ects_sem1
FROM subjects
WHERE semester = 1;

SELECT
  ROUND(
    100.0 * COUNT(*) FILTER (WHERE passed) / COUNT(*),
    2
  ) AS pass_rate_pct
FROM exams;

SELECT first_name, last_name, index_number
FROM students
WHERE id IN (
  SELECT student_id
  FROM exams
  WHERE grade > (
    SELECT AVG(grade) FROM exams
  )
)
ORDER BY last_name, first_name;
